class Solution:
    def minElement(self, nums):
        def digit_sum(x):
            s = 0
            while x > 0:
                s += x % 10
                x //= 10
            return s
        return min(digit_sum(x) for x in nums)

solutions.javascript:
var minElement = function(nums) {
    function digitSum(x) {
        let s = 0;
        while (x > 0) {
            s += x % 10;
            x = Math.floor(x / 10);
        }
        return s;
    }
    let best = Infinity;
    for (const x of nums) {
        const d = digitSum(x);
        if (d < best) best = d;
    }
    return best;
};
